INSERT INTO categories (id, name, description) VALUES
('cat-ml-foundations', 'ML Foundations', 'Core concepts that explain how machine learning models learn from data.'),
('cat-llm-concepts', 'LLM Concepts', 'Important ideas for understanding large language model behavior and usage.'),
('cat-inference-serving', 'Inference & Serving', 'How trained models are run, exposed, and optimized in applications.'),
('cat-data-training', 'Data & Training', 'Data-centric and optimization concepts used to train reliable AI systems.'),
('cat-ai-safety', 'AI Safety', 'Concepts for safer model behavior, risk management, and responsible usage.')
ON CONFLICT (id) DO UPDATE SET
    name = EXCLUDED.name,
    description = EXCLUDED.description;

INSERT INTO terms (
    id, slug, term, definition, explanation, humor, controversy_level,
    short_definition, full_explanation, category_id,
    tags, related_terms, example_usage, source, created_at, updated_at
) VALUES
('term-transformer', 'transformer', 'Transformer', 'A neural network architecture built around attention, designed to model relationships across a sequence without trudging through it one token at a time.', 'Transformers replaced older sequential approaches in many language tasks because they process sequences in parallel and learn which parts of the input matter to each other. That made them far easier to scale with more data, more compute, and larger model sizes.', 'The model architecture equivalent of showing up, firing recurrent loops, and saying: “Thanks, I''ll handle this faster.”', 0, 'A neural network architecture built around attention.', 'Transformers process sequences in parallel and learn relationships through attention layers instead of recurrent steps. They became the default architecture for modern LLMs because they scale well with data and compute.', 'cat-ml-foundations', 'neural-networks,attention,architecture', 'term-attention,term-token', 'Most current LLMs are Transformer-based.', 'Internal glossary seed', '2026-01-01T00:00:00Z', '2026-01-01T00:00:00Z'),
('term-attention', 'attention-mechanism', 'Attention Mechanism', 'A method that lets models focus on the parts of the input that actually matter instead of treating every token like it deserves equal drama.', 'Attention computes weighted relationships between tokens so the model can prioritize context that matters for the current prediction. Self-attention applies this within the same sequence, letting the model connect words that may be far apart but still deeply related.', 'A model''s version of selective hearing: suddenly very attentive, just not always to the part you hoped.', 0, 'A method that lets models focus on relevant input parts.', 'Attention computes weighted relationships between tokens so the model can prioritize context that matters for the current prediction. Self-attention applies this within the same sequence.', 'cat-ml-foundations', 'attention,context,transformer', 'term-transformer,term-token', 'Attention helps models connect distant words in a sentence.', 'Internal glossary seed', '2026-01-01T00:00:00Z', '2026-01-01T00:00:00Z'),
('term-token', 'token', 'Token', 'A unit of text a language model actually processes, because models do not read prose the way humans do; they chew through tokenized fragments.', 'Before training or inference, text is split into tokens according to a tokenizer vocabulary. Token count affects context-window usage, latency, and cost, which is why a short-looking prompt can still be more expensive than your intuition would like.', 'Like paying airline baggage fees, except the luggage is your prompt and every extra token somehow matters more than it should.', 0, 'A unit of text that a language model processes.', 'Before training or inference, text is split into tokens based on a tokenizer vocabulary. Token count affects context window usage, latency, and cost.', 'cat-llm-concepts', 'tokenization,llm,context-window', 'term-context-window,term-transformer', 'Prompt length is often measured in tokens, not characters.', 'Internal glossary seed', '2026-01-01T00:00:00Z', '2026-01-01T00:00:00Z'),
('term-context-window', 'context-window', 'Context Window', 'The maximum amount of tokenized context a model can consider at once before older or excess information starts getting chopped, summarized, or ignored.', 'A model context window limits how much input and prior output can be retained for a response. When the conversation grows past that limit, something has to give: truncation, summarization, or retrieval patterns step in because the model cannot magically remember everything just because the user wishes it would.', 'Like trying to fit a week of meetings onto a sticky note: eventually the important part gets squeezed out first.', 0, 'The maximum number of tokens a model can consider at once.', 'A model context window limits how much input and prior output can be retained for a response. Exceeding the limit requires truncation, summarization, or retrieval patterns.', 'cat-llm-concepts', 'llm,tokens,memory', 'term-token,term-rag', 'Long conversations can exceed the model context window.', 'Internal glossary seed', '2026-01-01T00:00:00Z', '2026-01-01T00:00:00Z'),
('term-rag', 'retrieval-augmented-generation-rag', 'Retrieval-Augmented Generation (RAG)', 'A pattern that retrieves external information before generation so the model stops pretending its frozen weights are a complete library.', 'RAG systems search a knowledge source for relevant documents and inject those results into the model''s context before it answers. This improves grounding and freshness without retraining the model, though it also adds retrieval quality, ranking, and context assembly as new failure points.', 'Because apparently “just know everything forever” was not a sustainable product strategy.', 1, 'A pattern that adds external knowledge retrieval before response generation.', 'RAG systems retrieve relevant documents from a knowledge source and inject them into model context, improving factual grounding and freshness without retraining the model.', 'cat-llm-concepts', 'rag,retrieval,llm', 'term-embedding,term-vector-database', 'A support bot can use RAG to answer product questions from documentation.', 'Internal glossary seed', '2026-01-01T00:00:00Z', '2026-01-01T00:00:00Z'),
('term-embedding', 'embedding', 'Embedding', 'A dense numeric representation of meaning that lets machines compare concepts mathematically instead of pretending keywords are enough.', 'Embeddings map text or other data into vector space so similar ideas end up numerically close together. They power semantic search, clustering, recommendation, and retrieval pipelines by giving systems a way to measure likeness without exact word overlap.', 'It is the art of turning meaning into math and then acting surprised when geometry starts deciding your search results.', 0, 'A dense numeric vector representing semantic meaning.', 'Embeddings map text or other data into vector space so similar concepts are numerically close. They are commonly used for semantic search, clustering, and retrieval pipelines.', 'cat-data-training', 'embeddings,vectors,semantic-search', 'term-vector-database,term-rag', 'Two semantically similar sentences should have nearby embeddings.', 'Internal glossary seed', '2026-01-01T00:00:00Z', '2026-01-01T00:00:00Z'),
('term-vector-database', 'vector-database', 'Vector Database', 'A database optimized for nearest-neighbor search over embeddings, built for the moment when ordinary lookup stops being enough.', 'Vector databases index embedding vectors so systems can retrieve items that are semantically similar rather than exactly matching a keyword. They are common in RAG pipelines because they make similarity search fast enough to be useful instead of theoretical.', 'A filing cabinet for vibes, except the vibes are vectors and the cabinet costs cloud money.', 0, 'A database optimized for nearest-neighbor search over vectors.', 'Vector databases index embedding vectors to support fast similarity search. They are frequently used as retrieval stores in RAG architectures.', 'cat-inference-serving', 'vector-search,retrieval,database', 'term-embedding,term-rag', 'A vector database returns the most similar chunks to a user query.', 'Internal glossary seed', '2026-01-01T00:00:00Z', '2026-01-01T00:00:00Z'),
('term-inference', 'inference', 'Inference', 'The process of running a trained model to produce outputs in the real world, where latency, cost, and user impatience suddenly become everyone''s problem.', 'Inference happens after training and can run in batch systems or interactive applications. Performance depends on model size, hardware, precision, batching strategy, and serving architecture, which is why “it worked in the notebook” is not the same as “it works in production.”', 'Training is the glamorous montage; inference is the day job that has to keep paying the bills.', 0, 'The process of running a trained model to produce outputs.', 'Inference happens after training and can run in batch or real-time systems. Performance factors include model size, hardware, precision, and serving strategy.', 'cat-inference-serving', 'inference,serving,latency', 'term-quantization,term-latency', 'Chat response generation is an inference workload.', 'Internal glossary seed', '2026-01-01T00:00:00Z', '2026-01-01T00:00:00Z'),
('term-quantization', 'quantization', 'Quantization', 'A technique that lowers model precision to cut memory and compute costs, usually by accepting that perfection is expensive and “good enough” ships faster.', 'Quantization converts model weights, and sometimes activations, into lower-bit formats. That can reduce latency and infrastructure costs substantially, but the quality tradeoff has to be measured instead of wished away.', 'Because sometimes the model does not need deluxe precision; it just needs to stop eating your GPU budget alive.', 1, 'A technique that reduces model precision to lower memory and compute costs.', 'Quantization converts model weights and sometimes activations to lower-bit formats, often reducing latency and infrastructure cost with manageable quality tradeoffs.', 'cat-inference-serving', 'optimization,latency,model-serving', 'term-inference,term-latency', 'Deploying an 8-bit model can reduce serving memory usage.', 'Internal glossary seed', '2026-01-01T00:00:00Z', '2026-01-01T00:00:00Z'),
('term-latency', 'latency', 'Latency', 'The time it takes a system to respond, which users interpret less as a metric and more as proof that your product is either smooth or painfully annoying.', 'In AI systems, latency combines network delay, retrieval time, queueing, and model generation time. Lowering it usually means making tradeoffs elsewhere, because performance tuning is rarely the story of getting everything you want for free.', 'Nothing reveals product truth faster than a spinner that stays on screen long enough for someone to sigh.', 0, 'The time required for a system to return a response.', 'In AI apps, latency combines network, retrieval, and model generation time. Lower latency improves user experience but often requires careful tradeoffs.', 'cat-inference-serving', 'performance,ux,serving', 'term-inference,term-quantization', 'Streaming tokens can improve perceived latency.', 'Internal glossary seed', '2026-01-01T00:00:00Z', '2026-01-01T00:00:00Z'),
('term-fine-tuning', 'fine-tuning', 'Fine-tuning', 'Additional training on task-specific data to make a pre-trained model better at your problem, rather than hoping vague prompting alone will perform miracles.', 'Fine-tuning adapts a general model to a specific task, tone, or domain. It can improve performance, but it also introduces data curation, evaluation, safety, and drift concerns that teams ignore at their own expense.', 'The corporate version of saying, “No, really, this time learn it my way.”', 1, 'Additional training of a pre-trained model on task-specific data.', 'Fine-tuning adapts general-purpose models for specialized tasks or domains. It can improve task performance but requires curation, evaluation, and safety checks.', 'cat-data-training', 'training,transfer-learning,adaptation', 'term-overfitting,term-evaluation', 'Teams fine-tune models for domain-specific support language.', 'Internal glossary seed', '2026-01-01T00:00:00Z', '2026-01-01T00:00:00Z'),
('term-overfitting', 'overfitting', 'Overfitting', 'When a model learns the training data too specifically and then falls apart on new inputs because memorization was mistaken for intelligence.', 'Overfitting happens when the model captures patterns, noise, or quirks that do not generalize beyond the training set. Validation discipline, regularization, and better data are the usual antidotes, though teams often discover the problem only after the demo confidence has already peaked.', 'Like acing yesterday''s quiz by memorizing the answer sheet and then bombing the real exam.', 0, 'When a model learns training data too specifically and generalizes poorly.', 'Overfitting occurs when a model memorizes training patterns that do not transfer to unseen data. Regularization, validation, and data diversity reduce this risk.', 'cat-data-training', 'generalization,training,evaluation', 'term-fine-tuning,term-evaluation', 'A model with high train accuracy but low test accuracy may be overfitting.', 'Internal glossary seed', '2026-01-01T00:00:00Z', '2026-01-01T00:00:00Z'),
('term-evaluation', 'model-evaluation', 'Model Evaluation', 'The process of measuring whether a model is actually good, not just impressive in a cherry-picked demo or suspiciously confident Slack message.', 'Evaluation combines automated metrics, benchmark datasets, regression tests, and scenario-based checks to assess quality, safety, and reliability. It matters before deployment and after every meaningful change, because model behavior is perfectly capable of regressing while everyone is busy celebrating.', 'The scientific method, reluctantly reintroduced to teams that were one meeting away from calling vibes a metric.', 1, 'The process of measuring model quality using defined metrics and tests.', 'Evaluation combines automated metrics and scenario-based checks to assess accuracy, safety, and reliability. It is necessary before and after deployment changes.', 'cat-data-training', 'metrics,benchmarking,quality', 'term-overfitting,term-hallucination', 'Prompt-based regression tests are part of model evaluation.', 'Internal glossary seed', '2026-01-01T00:00:00Z', '2026-01-01T00:00:00Z'),
('term-hallucination', 'hallucination', 'Hallucination', 'When a model produces information that sounds plausible, polished, and confident, while being wrong enough to cause trouble the moment someone trusts it.', 'Hallucinations are unsupported outputs that are not grounded in reliable evidence. They often look convincing because the model is optimizing for probable continuation, not truth, which is why retrieval, verification, and evaluation matter so much.', 'The AI equivalent of someone answering immediately, beautifully, and completely out of their depth.', 2, 'When a model generates incorrect or fabricated information confidently.', 'Hallucinations are unsupported outputs that appear plausible but are not grounded in reliable evidence. Mitigation includes retrieval, prompt design, and verification workflows.', 'cat-ai-safety', 'safety,reliability,grounding', 'term-rag,term-evaluation', 'Answer verification is important when hallucination risk is high.', 'Internal glossary seed', '2026-01-01T00:00:00Z', '2026-01-01T00:00:00Z'),
('term-guardrails', 'guardrails', 'Guardrails', 'Controls that constrain model behavior so the system does not wander off into unsafe, non-compliant, or simply embarrassing territory.', 'Guardrails can include policy rules, system instructions, moderation layers, validators, and post-processing checks. They do not make a model wise; they make it harder for bad behavior to reach the user without resistance.', 'Seatbelts for software that occasionally thinks the best answer is the one most likely to get legal involved.', 1, 'Controls that constrain model behavior and outputs.', 'Guardrails include policy filters, system prompts, validation checks, and moderation steps to reduce harmful or non-compliant responses in production systems.', 'cat-ai-safety', 'policy,safety,moderation', 'term-hallucination,term-red-teaming', 'A safety layer can block disallowed output categories.', 'Internal glossary seed', '2026-01-01T00:00:00Z', '2026-01-01T00:00:00Z'),
('term-red-teaming', 'red-teaming', 'Red Teaming', 'Structured adversarial testing meant to break the system before real users, bad actors, or reality do it for you.', 'Red teaming uses challenging, adversarial, or malicious scenarios to expose weaknesses in safety, robustness, and policy handling. It is less about proving the system is brilliant and more about discovering where it is fragile while you still have time to fix it.', 'Professionalized skepticism: hiring people to be difficult on purpose so production does not get to do it first.', 1, 'Structured adversarial testing of AI systems.', 'Red teaming probes systems with challenging or malicious scenarios to find vulnerabilities in safety, robustness, and policy compliance before broad release.', 'cat-ai-safety', 'safety,testing,robustness', 'term-guardrails,term-evaluation', 'Teams run red-team prompts before model launch.', 'Internal glossary seed', '2026-01-01T00:00:00Z', '2026-01-01T00:00:00Z')
ON CONFLICT (id) DO UPDATE SET
    slug = EXCLUDED.slug,
    term = EXCLUDED.term,
    definition = EXCLUDED.definition,
    explanation = EXCLUDED.explanation,
    humor = EXCLUDED.humor,
    controversy_level = EXCLUDED.controversy_level,
    short_definition = EXCLUDED.short_definition,
    full_explanation = EXCLUDED.full_explanation,
    category_id = EXCLUDED.category_id,
    tags = EXCLUDED.tags,
    related_terms = EXCLUDED.related_terms,
    example_usage = EXCLUDED.example_usage,
    source = EXCLUDED.source,
    created_at = EXCLUDED.created_at,
    updated_at = EXCLUDED.updated_at;

